import type { FormMode } from '../components/form/FormMode';
import { FormMode as FormModeEnum } from '../components/form/FormMode';
import type { VoucherToolbarDisabledReasons, VoucherViewModeHint } from '../components/voucher/voucherToolbarTypes';

export type { VoucherViewModeHint } from '../components/voucher/voucherToolbarTypes';

/** Mức xử lý cuối (phê duyệt + hoạch toán) — `voucher-setup-master.md`. */
export const VOUCHER_FINAL_PROCESSING_LEVEL = '9';

export function isFinalProcessingLevel(level: string | undefined | null): boolean {
  return String(level ?? '').trim() === VOUCHER_FINAL_PROCESSING_LEVEL;
}

/** Posted / Cancelled / Issued — không sửa. */
export function isVoucherDocumentTerminalLocked(status: string): boolean {
  return status === 'Cancelled' || status === 'Posted';
}

export function isSalesInvoiceLocked(status: string): boolean {
  return status !== 'Draft';
}

/**
 * Hint View duy nhất — ưu tiên «nhấn Sửa» khi toolbar cho phép Edit; ngược lại khóa theo lý do.
 */
export function resolveVoucherViewModeHint(input: {
  formMode: FormMode;
  isNew: boolean;
  status: string;
  processingLevel: string;
  canEditWhenView: boolean;
}): VoucherViewModeHint | null {
  if (input.isNew || input.formMode !== FormModeEnum.View) return null;

  if (input.canEditWhenView) {
    return { kind: 'editable' };
  }

  if (input.status === 'Posted') {
    return { kind: 'locked', message: 'Chỉ xem — đã ghi sổ' };
  }
  if (input.status === 'Cancelled') {
    return { kind: 'locked', message: 'Chỉ xem — đã hủy' };
  }
  if (isFinalProcessingLevel(input.processingLevel)) {
    return { kind: 'locked', message: 'Chỉ xem — mức xử lý Hoạch toán sổ cái' };
  }

  return { kind: 'locked', message: 'Chỉ xem — không thể chỉnh sửa' };
}

/** Tooltip nút toolbar disabled — dùng chung mọi form chứng từ (`voucher-form-toolbar.md`). */
export function buildVoucherToolbarDisabledReasons(input: {
  isNew: boolean;
  status: string;
  isStatusLocked: boolean;
  draftOnlyMessage?: string;
}): VoucherToolbarDisabledReasons {
  const draftOnly =
    input.status !== 'Draft'
      ? (input.draftOnlyMessage ?? 'Chỉ thao tác trên chứng từ ở trạng thái Nháp')
      : undefined;
  return {
    approve: input.isNew ? 'Lưu chứng từ trước khi phê duyệt' : draftOnly,
    post: input.isNew
      ? 'Lưu chứng từ trước khi ghi sổ'
      : draftOnly,
    copy: input.isNew ? 'Lưu chứng từ trước khi sao chép' : undefined,
    print: input.isNew ? 'Lưu chứng từ trước khi in' : undefined,
    history: input.isNew ? 'Lưu chứng từ trước khi xem lịch sử' : undefined,
    edit: input.isStatusLocked ? 'Chỉ xem — đã ghi sổ hoặc đã hủy' : undefined,
    delete: input.isNew ? undefined : input.status !== 'Draft' ? 'Chỉ xóa chứng từ Nháp' : undefined,
  };
}
