import { scrollToValidationTarget } from '@linm-soft-org/linm-web-common-components';

function scrollToFieldById(id: string): void {
  scrollToValidationTarget(id, 80);
}

export type InvoiceFieldErrors = {
  customerId?: string;
  lines?: string;
};

export type InvoiceValidateInput = {
  customerId?: string;
  requireCustomerId?: boolean;
  customerLabel?: string;
  linesCount: number;
};

export function validateInvoiceFields(input: InvoiceValidateInput): {
  fieldErrors: InvoiceFieldErrors;
  bannerMessages: string[];
} {
  const fieldErrors: InvoiceFieldErrors = {};
  const bannerMessages: string[] = [];

  if (input.requireCustomerId && !input.customerId?.trim()) {
    const label = input.customerLabel?.trim() || 'Khách hàng';
    const msg = `${label} là bắt buộc`;
    fieldErrors.customerId = msg;
    bannerMessages.push(msg);
  }

  if (input.linesCount === 0) {
    bannerMessages.push('Phải có ít nhất 1 dòng hàng hóa');
  }

  return { fieldErrors, bannerMessages };
}

export function scrollToFirstInvoiceFieldError(
  fieldErrors: InvoiceFieldErrors,
  tid: (suffix: string) => string,
  validationBannerId: string,
): void {
  const keys = Object.keys(fieldErrors) as (keyof InvoiceFieldErrors)[];
  for (const key of keys) {
    const error = fieldErrors[key];
    if (error && key !== 'lines') {
      scrollToFieldById(tid(`field-${key}`));
      return;
    }
  }
  scrollToValidationTarget(validationBannerId, 16);
}
